import './TransactionList.css';

function TransactionList({transaction, transactions, setTransactions}) {
    function deleteTransaction() {
        setTransactions(transactions.filter(t => t.id !== transaction.id)
        );
    }
    return (
        <div className="transaction-list-row">
            <div className="details">
                <div className='transaction-list-type'><p>Type: </p> {transaction.type}</div>
                <div className='transaction-list-category'><p>Category: </p>{transaction.category}</div>
                <div className='transaction-list-amount'><p>Amount: </p>₹{transaction.amount}</div>
                <div className='transaction-list-date'><p>Date: </p>{transaction.date}</div>
                <button className='delete-transaction-list-button' onClick={deleteTransaction}>X Delete</button>
                <div className='transaction-description'><p>Description: </p>{transaction.description}</div>
            </div>
        </div>
    )
};

export default TransactionList;
